// ─────────────────────────────────────────────
// RAG STATUS CALCULATOR
// Reads summary row from each project sheet
// Returns array of project health objects
// ─────────────────────────────────────────────

const allItems = $input.all();

// Each item is one row from merged sheets
// We look for the summary row (where column A = 'project_name')
// that is the header, and the next row is the data.

// Collect all rows across all inputs
const projects = [];

for (const item of allItems) {
  const row = item.json;

  // The summary data row has numeric budget values
  // Skip header rows and empty rows
  if (!row.project_name || row.project_name === 'project_name') continue;
  if (typeof row.budget_total === 'string' && isNaN(parseFloat(row.budget_total))) continue;

  const name = row.project_name || 'Unknown Project';
  const plannedEnd = row.planned_end || '';
  const forecastEnd = row.forecast_end || '';
  const budgetTotal = parseFloat(String(row.budget_total).replace(/[^0-9.]/g, '')) || 0;
  const budgetSpent = parseFloat(String(row.budget_spent).replace(/[^0-9.]/g, '')) || 0;
  const openIssues = parseInt(row.open_issues_count) || 0;
  const pctComplete = parseFloat(String(row.pct_complete).replace('%', '')) || 0;

  // ── Budget Burn % ──
  const burnPct = budgetTotal > 0 ? (budgetSpent / budgetTotal) * 100 : 0;

  // ── Schedule Variance in days ──
  let scheduleVarianceDays = 0;
  let scheduleVarianceText = 'On Track';
  if (plannedEnd && forecastEnd) {
    const planned = new Date(plannedEnd);
    const forecast = new Date(forecastEnd);
    scheduleVarianceDays = Math.round((forecast - planned) / (1000 * 60 * 60 * 24));
    scheduleVarianceText = scheduleVarianceDays > 0
      ? `+${scheduleVarianceDays} days late`
      : scheduleVarianceDays < 0
        ? `${Math.abs(scheduleVarianceDays)} days early`
        : 'On Schedule';
  }

  // ── RAG Scoring ──
  // Each dimension scores: 0=Green, 1=Amber, 2=Red
  let scheduleScore = 0;
  if (scheduleVarianceDays > 30) scheduleScore = 2;
  else if (scheduleVarianceDays > 0) scheduleScore = 1;

  let budgetScore = 0;
  if (burnPct > 90) budgetScore = 2;
  else if (burnPct > 75) budgetScore = 1;

  let issuesScore = 0;
  if (openIssues >= 4) issuesScore = 2;
  else if (openIssues >= 2) issuesScore = 1;

  const totalScore = scheduleScore + budgetScore + issuesScore;

  let ragStatus, ragEmoji, ragColor;
  if (totalScore >= 4) {
    ragStatus = 'RED';
    ragEmoji = '🔴';
    ragColor = '#C00000';
  } else if (totalScore >= 2) {
    ragStatus = 'AMBER';
    ragEmoji = '🟡';
    ragColor = '#ED7D31';
  } else {
    ragStatus = 'GREEN';
    ragEmoji = '🟢';
    ragColor = '#1A7340';
  }

  projects.push({
    name,
    plannedEnd,
    forecastEnd,
    budgetTotal,
    budgetSpent,
    burnPct: burnPct.toFixed(1),
    openIssues,
    pctComplete,
    scheduleVarianceDays,
    scheduleVarianceText,
    ragStatus,
    ragEmoji,
    ragColor,
    // Pass to AI prompt
    aiPrompt: `Project: ${name}\nRAG Status: ${ragStatus}\nSchedule: ${scheduleVarianceText}\nBudget Burn: ${burnPct.toFixed(1)}% (Spent $${budgetSpent.toLocaleString()} of $${budgetTotal.toLocaleString()})\nOpen Issues: ${openIssues}\n% Complete: ${pctComplete}%\n\nWrite a concise 3-line executive health summary for this project. Line 1: Overall status assessment. Line 2: Key risk or concern. Line 3: Recommended action for leadership. Be direct and specific. No bullet points.`
  });
}

// Return one item per project for the loop
return projects.map(p => ({ json: p }));

// ─────────────────────────────────────────────
// Attach AI narrative back to project data
// n8n OpenAI node returns message in content[0].text
// ─────────────────────────────────────────────
const items = $input.all();
const results = [];

for (const item of items) {
  const proj = item.json;
  // Extract the text from the OpenAI response
  const aiText = proj?.choices?.[0]?.message?.content ||
                 proj?.message?.content ||
                 proj?.content ||
                 'Summary not available.';
  results.push({
    json: {
      ...proj,
      aiNarrative: aiText.trim()
    }
  });
}

return results;
